package com.golfperformance.app.data.local

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import androidx.room.migration.Migration
import androidx.sqlite.db.SupportSQLiteDatabase

@Database(entities = [PlayerEntity::class, ShotEntity::class], version = 2, exportSchema = false)
abstract class AppDatabase : RoomDatabase() {
    abstract fun playerDao(): PlayerDao

    companion object {
        @Volatile
        private var INSTANCE: AppDatabase? = null

        private val MIGRATION_1_2 = object : Migration(1, 2) {
            override fun migrate(database: SupportSQLiteDatabase) {
                // Add the spinRate column to the shots table with a default value so existing rows are preserved
                database.execSQL("ALTER TABLE shots ADD COLUMN spinRate REAL NOT NULL DEFAULT 0.0")
            }
        }

        fun getInstance(context: Context): AppDatabase =
            INSTANCE ?: synchronized(this) {
                INSTANCE ?: Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    "golf_performance.db"
                ).addMigrations(MIGRATION_1_2).build().also { INSTANCE = it }
            }
    }
}

package com.golfperformance.app.data.local

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import kotlinx.coroutines.flow.Flow

@Dao
interface PlayerDao {
    @Query("SELECT * FROM players ORDER BY name")
    fun playersFlow(): Flow<List<PlayerEntity>>

    @Query("SELECT * FROM players WHERE name LIKE :query OR club LIKE :query ORDER BY name")
    fun playersFlowFiltered(query: String): Flow<List<PlayerEntity>>

    @Query("SELECT * FROM players WHERE club = :club ORDER BY name")
    fun playersFlowByClub(club: String): Flow<List<PlayerEntity>>

    @Query("SELECT DISTINCT club FROM players ORDER BY club")
    fun distinctClubsFlow(): Flow<List<String>>

    @Query("SELECT * FROM shots WHERE playerId = :playerId ORDER BY id")
    fun shotsForPlayer(playerId: String): Flow<List<ShotEntity>>

    @Query("SELECT * FROM players WHERE id = :playerId LIMIT 1")
    fun playerByIdFlow(playerId: String): Flow<PlayerEntity?>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertPlayers(players: List<PlayerEntity>)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertShots(shots: List<ShotEntity>)
}

package com.golfperformance.app.data.local
import androidx.room.Entity import androidx.room.PrimaryKey
@Entity(tableName = "players") data class PlayerEntity( @PrimaryKey val id: String, val name: String, val club: String, val imageUrl: String, val avgBallSpeed: Double )
@Entity(tableName = "shots") data class ShotEntity( @PrimaryKey val id: String, val playerId: String, val ballSpeed: Double, val launchAngle: Double, val carryDistance: Double, val spinRate: Double, val club: String )

package com.golfperformance.app.data.remote

import android.content.Context
import okhttp3.Interceptor
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.Protocol
import okhttp3.Response
import okhttp3.ResponseBody.Companion.toResponseBody

/**
 * Simple interceptor that serves a mock players JSON from the app assets for the /players endpoint.
 * This simulates a REST API without relying on external services.
 */
class MockInterceptor(private val context: Context) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val path = request.url.encodedPath

        if (path.endsWith("/players")) {
            val json = context.assets.open("mock_players.json").bufferedReader().use { it.readText() }
            val body = json.toResponseBody("application/json".toMediaType())
            return Response.Builder()
                .request(request)
                .protocol(Protocol.HTTP_1_1)
                .code(200)
                .message("OK")
                .body(body)
                .build()
        }

        return chain.proceed(request)
    }
}

package com.golfperformance.app.di

import android.content.Context
import com.golfperformance.app.data.local.AppDatabase
import com.golfperformance.app.data.local.PlayerDao
import com.golfperformance.app.data.remote.ApiService
import com.golfperformance.app.data.remote.MockInterceptor
import com.golfperformance.app.repository.PlayerRepository
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.moshi.MoshiConverterFactory
import com.squareup.moshi.Moshi
import com.squareup.moshi.kotlin.reflect.KotlinJsonAdapterFactory
import org.koin.dsl.module

val appModule = module {
    single { provideOkHttpClient(get()) }
    single { provideRetrofit(get()).create(ApiService::class.java) }
    single { AppDatabase.getInstance(get()) }
    single { get<AppDatabase>().playerDao() }
    single { PlayerRepository(get(), get()) }
}

fun provideOkHttpClient(context: Context): OkHttpClient {
    val logging = HttpLoggingInterceptor().apply { setLevel(HttpLoggingInterceptor.Level.BASIC) }
    return OkHttpClient.Builder()
        .addInterceptor(MockInterceptor(context))
        .addInterceptor(logging)
        .build()
}

fun provideRetrofit(okHttpClient: OkHttpClient): Retrofit {
    val moshi = Moshi.Builder()
        .add(KotlinJsonAdapterFactory())
        .build()
    return Retrofit.Builder()
        .baseUrl("https://api.local/")
        .client(okHttpClient)
        .addConverterFactory(MoshiConverterFactory.create(moshi))
        .build()
}

package com.golfperformance.app.repository

import com.golfperformance.app.data.local.PlayerDao
import com.golfperformance.app.data.local.PlayerEntity
import com.golfperformance.app.data.local.ShotEntity
import com.golfperformance.app.data.remote.ApiService
import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.withContext

class PlayerRepository(
    private val api: ApiService,
    private val dao: PlayerDao,
    private val ioDispatcher: CoroutineDispatcher = Dispatchers.IO
) {
    fun playersFlow(): Flow<List<PlayerEntity>> = dao.playersFlow()

    fun playersFlowFiltered(query: String): Flow<List<PlayerEntity>> = dao.playersFlowFiltered(query)

    fun playersFlowByClub(club: String): Flow<List<PlayerEntity>> = dao.playersFlowByClub(club)

    fun shotsForPlayer(playerId: String): Flow<List<ShotEntity>> = dao.shotsForPlayer(playerId)

    fun playerById(playerId: String): Flow<PlayerEntity?> = dao.playerByIdFlow(playerId)

    fun clubsFlow(): Flow<List<String>> = dao.distinctClubsFlow()

    suspend fun refreshFromRemote() = withContext(ioDispatcher) {
        val playersDto = api.getPlayers()
        val players = playersDto.map { dto ->
            val avgSpeed = if (dto.shots.isNotEmpty()) dto.shots.map { it.ballSpeed }.average() else 0.0
            PlayerEntity(dto.id, dto.name, dto.club, dto.imageUrl, avgSpeed)
        }
        val shots = playersDto.flatMap { dto ->
            dto.shots.map { s ->
                ShotEntity(s.id, dto.id, s.ballSpeed, s.launchAngle, s.carryDistance, s.spinRate, s.club)
            }
        }

        dao.insertPlayers(players)
        dao.insertShots(shots)
    }
}

