import androidx.compose.runtime.setValue

@Composable
fun PlayerListScreen(onPlayerClick: (String) -> Unit) {
    val repo: PlayerRepository = GlobalContext.get().get()
    val factory = remember { PlayerViewModelFactory(repo) }
    val vm: PlayerViewModel = viewModel(factory = factory)

    LaunchedEffect(Unit) { vm.refresh() }

    var search by remember { mutableStateOf("") }
    val players by vm.players.collectAsState()
    val clubs by vm.clubs.collectAsState()
    var selectedClub by remember { mutableStateOf("") }

    // update viewmodel when search changes
    LaunchedEffect(search) { vm.setQuery(search) }

    Column(modifier = Modifier.padding(8.dp)) {
        // Club filter row with horizontal scroll (LazyRow)
        LazyRow(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.padding(8.dp)) {
            item {
                val allSelected = selectedClub.isEmpty()
                FilterChip(
                    selected = allSelected,
                    onClick = {
                        vm.setClub("")
                        selectedClub = ""
                    },
                    label = { Text("All") },
                    colors = FilterChipDefaults.filterChipColors(
                        selectedContainerColor = MaterialTheme.colorScheme.primary,
                        selectedLabelColor = MaterialTheme.colorScheme.onPrimary
                    )
                )
            }

            items(clubs) { club ->
                val isSelected = selectedClub == club
                FilterChip(
                    selected = isSelected,
                    onClick = {
                        vm.setClub(club)
                        selectedClub = club
                    },
                    label = { Text(club) },
                    colors = FilterChipDefaults.filterChipColors(
                        selectedContainerColor = MaterialTheme.colorScheme.primary,
                        selectedLabelColor = MaterialTheme.colorScheme.onPrimary
                    )
                )
            }
        }

        TextField(value = search, onValueChange = { search = it }, label = { Text("Search") }, modifier = Modifier.fillMaxWidth().padding(8.dp))

        LazyColumn(modifier = Modifier.weight(1f)) {
        items(players) { player ->
            Card(modifier = Modifier
                .fillMaxWidth()
                .padding(8.dp)
                .clickable(
                    indication = null,
                    interactionSource = remember { MutableInteractionSource() }
                ) { onPlayerClick(player.id) }
            ) {
                Row(modifier = Modifier.padding(12.dp)) {
                    val ctx = LocalContext.current
                    AsyncImage(
                        model = ImageRequest.Builder(ctx)
                            .data(player.imageUrl)
                            .crossfade(false)
                            .build(),
                        contentDescription = "Player",
                        modifier = Modifier.size(56.dp)
                    )
                    Spacer(modifier = Modifier.size(8.dp))
                    Column {
                        Text(text = player.name, style = MaterialTheme.typography.titleMedium)
                        Text(text = "Club: ${player.club}")
                        Text(text = "Avg speed: ${String.format("%.1f", player.avgBallSpeed)} mph")
                    }
                }
            }
        }
    }
    }
}

package com.golfperformance.app.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.golfperformance.app.data.local.ShotEntity
import com.golfperformance.app.repository.PlayerRepository
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.launch

@OptIn(ExperimentalCoroutinesApi::class)
class PlayerViewModel(private val repository: PlayerRepository) : ViewModel() {
    private val _query = MutableStateFlow("")

    // Expose players as a StateFlow that updates when the search query changes
    val players: StateFlow<List<com.golfperformance.app.data.local.PlayerEntity>> =
        _query
            .flatMapLatest { q ->
                if (q.isBlank()) repository.playersFlow() else repository.playersFlowFiltered("%${q}%")
            }
            .stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())

    fun refresh() {
        viewModelScope.launch {
            repository.refreshFromRemote()
        }
    }

    fun shotsForPlayer(playerId: String): StateFlow<List<ShotEntity>> {
        return repository.shotsForPlayer(playerId)
            .stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())
    }

    fun setQuery(q: String) {
        _query.value = q
    }
}

package com.golfperformance.app.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.golfperformance.app.data.local.ShotEntity
import com.golfperformance.app.data.local.PlayerEntity
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.stateIn
import com.golfperformance.app.repository.PlayerRepository
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.launch

@OptIn(ExperimentalCoroutinesApi::class)
class PlayerViewModel(private val repository: PlayerRepository) : ViewModel() {
    private val _query = MutableStateFlow("")
    private val _club = MutableStateFlow("")

    // Expose players as a StateFlow that updates when the search query or club filter changes
    val players: StateFlow<List<PlayerEntity>> =
        combine(_query, _club) { q, c -> q to c }
            .flatMapLatest { (q, c) ->
                when {
                    c.isNotBlank() -> repository.playersFlowByClub(c)
                    q.isBlank() -> repository.playersFlow()
                    else -> repository.playersFlowFiltered("%${q}%")
                }
            }
            .stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())

    val clubs: StateFlow<List<String>> =
        repository.clubsFlow().stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())

    fun refresh() {
        viewModelScope.launch {
            repository.refreshFromRemote()
        }
    }

    fun shotsForPlayer(playerId: String): StateFlow<List<ShotEntity>> {
        return repository.shotsForPlayer(playerId)
            .stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())
    }

    fun playerForId(playerId: String): StateFlow<PlayerEntity?> {
        return repository.playerById(playerId)
            .stateIn(viewModelScope, SharingStarted.Eagerly, null)
    }

    fun setQuery(q: String) {
        _query.value = q
    }

    fun setClub(c: String) {
        _club.value = c
    }
}

package com.golfperformance.app.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import com.golfperformance.app.repository.PlayerRepository

class PlayerViewModelFactory(private val repository: PlayerRepository) : ViewModelProvider.Factory {
    @Suppress("UNCHECKED_CAST")
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(PlayerViewModel::class.java)) {
            return PlayerViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

